        for (int i = 0; i < CAPACITY; i++) bins[i] = new java.util.ArrayList<>();
    }

    private int hash(int key) { return Math.abs(key) % CAPACITY; }

    public void put(int key, String value) {
        int bin = hash(key);
        for (Object[] entry : bins[bin]) {
            if ((int) entry[0] == key) { entry[1] = value; return; } // update
        }
        // TODO: add new entry {key, value} to bins[bin]; increment size
    }

    public String get(int key) {
        int bin = hash(key);
        for (Object[] entry : bins[bin]) {
            if ((int) entry[0] == key) return (String) entry[1];
        }
        return null;
    }

    public boolean remove(int key) {
        int bin = hash(key);
        // TODO: iterate bins[bin], remove the entry with matching key, decrement size, return true; return false if not found
        for (int i = 0; i < bins[bin].size(); i++) {
            if ((int) bins[bin].get(i)[0] == key) {
                bins[bin].remove(i); size--; return true;
            }
        }
        return false;
    }

    public int size() { return size; }

    public static void main(String[] args) {
        HashTableChaining ht = new HashTableChaining();
        ht.put(1, "one"); ht.put(9, "nine"); ht.put(17, "seventeen"); // 1,9,17 all hash to 1
