        System.out.println("size: " + ht.size());
    }
}

import java.util.*;

public class RehashTable {
    private int capacity;
    private List<int[]>[] bins; // {key, value} pairs
    private int size;
    private static final double LOAD_THRESHOLD = 0.75;

    @SuppressWarnings("unchecked")
    public RehashTable(int initial) {
        capacity = initial;
        bins = new ArrayList[capacity];
        for (int i = 0; i < capacity; i++) bins[i] = new ArrayList<>();
    }

    private int hash(int key) { return Math.abs(key) % capacity; }

    @SuppressWarnings("unchecked")
    private void rehash() {
        System.out.printf("Rehashing: capacity %d -> %d (load=%.2f)%n",
                          capacity, capacity*2, (double)size/capacity);
        List<int[]>[] old = bins;
        capacity *= 2;
        bins = new ArrayList[capacity];
        for (int i = 0; i < capacity; i++) bins[i] = new ArrayList<>();
        size = 0;
        for (List<int[]> bin : old)
            for (int[] e : bin) putInternal(e[0], e[1]);
    }

    private void putInternal(int key, int val) {
        int b = hash(key);
        for (int[] e : bins[b]) if (e[0]==key) { e[1]=val; return; }
        bins[b].add(new int[]{key, val}); size++;
    }

    public void put(int key, int val) {
        putInternal(key, val);
        // TODO: if load factor > LOAD_THRESHOLD, call rehash()
    }

    public int get(int key) {
        for (int[] e : bins[hash(key)]) if (e[0]==key) return e[1];
        return -1;
    }

    public double loadFactor() { return (double) size / capacity; }

    public static void main(String[] args) {
        RehashTable rt = new RehashTable(4);
        System.out.println("Initial capacity: 4");
        for (int i = 1; i <= 8; i++) {
            rt.put(i, i * 10);
            System.out.printf("put(%d): size=%d cap=%d load=%.2f%n", i, rt.size, rt.capacity, rt.loadFactor());
        }
        System.out.println("get(5): " + rt.get(5));
    }
}

